worktree_state.content:
{
  "$schema": "https://e-menum.net/schemas/module-v1.json",
  "id": "ai",
  "name": "AI Module",
  "version": "0.0.0",
  "status": "stub",
  "description": "Yapay zeka özellikleri - içerik üretimi, akıllı öneriler ve tahminleme",

  "type": "feature",
  "category": "ai",

  "author": {
    "name": "E-Menum Team",
    "email": "dev@e-menum.net"
  },

  "compatibility": {
    "platform": ">=1.0.0",
    "node": ">=20.0.0"
  },

  "dependencies": {
    "modules": ["auth", "organization", "menu"],
    "optional": ["media", "analytics"]
  },

  "provides": {
    "services": ["IAIService", "IContentGeneratorService"],
    "events": [
      "ai.content.generated",
      "ai.suggestion.created",
      "ai.analysis.completed"
    ],
    "hooks": [
      "afterItemCreate",
      "beforeMenuPublish"
    ],
    "permissions": [
      "ai:generate",
      "ai:configure",
      "ai:view_suggestions"
    ]
  },

  "tier": {
    "minimum": "professional",
    "features": {
      "professional": ["content_generation", "basic_suggestions"],
      "business": ["content_generation", "basic_suggestions", "image_analysis", "translation"],
      "enterprise": ["content_generation", "basic_suggestions", "image_analysis", "translation", "custom_models", "advanced_analytics"]
    }
  },

  "plannedFeatures": [
    "Menu item description generation",
    "Product image analysis",
    "Smart pricing suggestions",
    "Demand forecasting",
    "Automatic translation",
    "Allergen detection from images",
    "Menu optimization suggestions",
    "Customer preference analysis"
  ],

  "estimatedRelease": "Q3 2026"
}
